// Counties served by the same center as `county` (for map highlight + "Serves:").

export const siblingCounties = (county) => {

  const rc = COUNTY_TO_RC[county]

  return rc && rc !== 'la' ? COUNTIES.filter((c) => COUNTY_TO_RC[c] === rc) : (county ? [county] : [])

}

